import requests
from requests.exceptions import RequestException

BASE_URL = "http://localhost:8000"
TIMEOUT = 30


def test_ingest_pdf_document_pipeline():
    ingest_url = f"{BASE_URL}/ingest"

    # Valid request payload includes all required fields
    valid_payload = {
        "pdf_path": "data/raw/acts/R.S.C., 1985, c. P-21 - Privacy Act.pdf",
        "document_type": "act",
        "jurisdiction": "Canada",
        "is_bilingual": True
    }

    # Invalid request payloads
    invalid_payloads = [
        # Bad path
        {
            "pdf_path": "data/raw/acts/nonexistent.pdf",
            "document_type": "act",
            "jurisdiction": "Canada"
        },
        # Missing parameters
        {
            "pdf_path": "data/raw/acts/R.S.C., 1985, c. P-21 - Privacy Act.pdf"
            # missing document_type, jurisdiction, is_bilingual
        },
        {
            "document_type": "act",
            "jurisdiction": "Canada"
            # missing pdf_path, is_bilingual
        },
        {
            # empty payload
        }
    ]

    # Test successful ingestion with expected response keys
    try:
        response = requests.post(ingest_url, json=valid_payload, timeout=TIMEOUT)
        assert response.status_code == 200, f"Expected 200, got {response.status_code}"
        json_resp = response.json()
        expected_keys = {"document_id", "sections_count", "status"}
        # Assert required keys present (allow extra keys)
        assert expected_keys.issubset(set(json_resp.keys())), f"Response keys missing required keys. Expected at least keys {expected_keys}, got {set(json_resp.keys())}"
        # Check types
        assert isinstance(json_resp["document_id"], str), "document_id should be string"
        assert isinstance(json_resp["sections_count"], int), "sections_count should be integer"
        assert json_resp["status"] == "processed", f"status should be 'processed', got {json_resp['status']}"
    except RequestException as e:
        assert False, f"RequestException during valid ingest test: {e}"
    except ValueError:
        assert False, "Response is not valid JSON for valid ingest test"

    # Test error handling for invalid payloads (expect 400)
    for payload in invalid_payloads:
        try:
            resp = requests.post(ingest_url, json=payload, timeout=TIMEOUT)
            assert resp.status_code == 400, f"Expected 400 for payload {payload}, got {resp.status_code}"
            # No strict assertion on response content text
        except RequestException as e:
            assert False, f"RequestException during invalid ingest test with payload {payload}: {e}"
        except Exception as e:
            assert False, f"Unexpected exception during invalid ingest test with payload {payload}: {e}"


test_ingest_pdf_document_pipeline()

import requests

BASE_URL = "http://localhost:8000"
TIMEOUT = 30
HEADERS = {"Content-Type": "application/json"}

def test_email_signup_submission():
    url = f"{BASE_URL}/api/submit-email"

    # Test valid email submission
    valid_payload = {"email": "test@example.com"}
    try:
        response = requests.post(url, json=valid_payload, headers=HEADERS, timeout=TIMEOUT)
        assert response.status_code == 200, f"Expected status 200 for valid email but got {response.status_code}"
        json_resp = response.json()
        assert "success" in json_resp, "'success' key not in response"
        assert json_resp["success"] is True, "Expected success true for valid email submission"
    except requests.RequestException as e:
        assert False, f"Request failed for valid email: {e}"

    # Test invalid email submissions
    invalid_emails = ["not-an-email", "missing_at_symbol.com", "@missingusername.com", "plainaddress"]
    for invalid_email in invalid_emails:
        invalid_payload = {"email": invalid_email}
        try:
            response = requests.post(url, json=invalid_payload, headers=HEADERS, timeout=TIMEOUT)
            assert response.status_code == 400, f"Expected status 400 for invalid email '{invalid_email}' but got {response.status_code}"
        except requests.RequestException as e:
            assert False, f"Request failed for invalid email '{invalid_email}': {e}"

    # Test server error handling by simulating a server error scenario:
    # Since no details given on how to trigger a 500, we perform a request with missing email field
    try:
        response = requests.post(url, json={}, headers=HEADERS, timeout=TIMEOUT)
        # We expect 400 or 422 (validation error) or 500 - if 500 occurs, test passes for server error handling
        assert response.status_code in (400, 422, 500), f"Expected 400, 422 or 500 status for missing email field but got {response.status_code}"
    except requests.RequestException as e:
        assert False, f"Request failed for missing email field: {e}"

test_email_signup_submission()
